@page "/category/{Slug}"

<PageTitle>@GetCategoryName() - RecipeHub</PageTitle>

<h1>@GetCategoryName()</h1>
<p class="text-muted">Browse our collection of @GetCategoryName().ToLower() recipes.</p>

<div class="row">
    @foreach (var recipe in GetRecipes())
    {
        <div class="col-md-6 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@recipe.Title</h5>
                    <p class="card-text">@recipe.Description</p>
                    <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                </div>
            </div>
        </div>
    }
</div>

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string Slug { get; set; } = "";

    private string GetCategoryName() => Slug switch
    {
        "appetizers" => "Appetizers",
        "main-courses" => "Main Courses",
        "desserts" => "Desserts",
        "beverages" => "Beverages",
        "baking" => "Baking",
        "vegetarian" => "Vegetarian",
        _ => "Recipes"
    };

    private List<RecipeInfo> GetRecipes() => Slug switch
    {
        "appetizers" => new()
        {
            new("bruschetta", "Classic Bruschetta", "Toasted bread with fresh tomatoes, basil, and garlic."),
            new("spinach-dip", "Spinach Artichoke Dip", "Creamy baked dip with spinach and artichoke hearts."),
        },
        "main-courses" => new()
        {
            new("spaghetti-bolognese", "Spaghetti Bolognese", "Traditional Italian meat sauce over pasta."),
            new("grilled-salmon", "Grilled Salmon", "Herb-crusted salmon fillet with lemon butter."),
        },
        "desserts" => new()
        {
            new("chocolate-cake", "Chocolate Lava Cake", "Rich molten chocolate cake with a gooey center."),
            new("tiramisu", "Classic Tiramisu", "Italian coffee-flavored layered dessert."),
        },
        "beverages" => new()
        {
            new("smoothie", "Berry Smoothie", "Fresh mixed berry smoothie with yogurt."),
            new("iced-coffee", "Vietnamese Iced Coffee", "Strong coffee with sweetened condensed milk."),
        },
        "baking" => new()
        {
            new("sourdough", "Sourdough Bread", "Artisan sourdough with a crispy crust."),
            new("croissants", "Butter Croissants", "Flaky, buttery French croissants."),
        },
        "vegetarian" => new()
        {
            new("veggie-stir-fry", "Vegetable Stir Fry", "Colorful vegetables in a savory sauce."),
            new("mushroom-risotto", "Mushroom Risotto", "Creamy arborio rice with wild mushrooms."),
        },
        _ => new()
    };

    private record RecipeInfo(string Id, string Title, string Description);
}

@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= CurrentRating ? "filled" : "")"
              @onclick="() => SetRating(star)"
              role="button"
              title="@star star(s)">
            @(star <= CurrentRating ? "★" : "☆")
        </span>
    }
</div>

@if (CurrentRating > 0)
{
    <p class="mt-2 text-success">You rated this recipe @CurrentRating / 5 stars!</p>
}
else
{
    <p class="mt-2 text-muted">Click a star to rate.</p>
}

@code {
    [Parameter]
    public string RecipeId { get; set; } = "";

    private int CurrentRating { get; set; }

    private void SetRating(int rating)
    {
        CurrentRating = rating;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@Model.Title</strong>" with the community.</p>
        <button class="btn btn-primary" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
                <option value="Beverages">Beverages</option>
                <option value="Baking">Baking</option>
                <option value="Vegetarian">Vegetarian</option>
            </InputSelect>
            <ValidationMessage For="() => Model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Model.Ingredients"
                           placeholder="Enter one ingredient per line" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
            <div class="form-text">Enter one ingredient per line.</div>
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Model.Steps"
                           placeholder="Enter one step per line" />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
            <div class="form-text">Enter one step per line.</div>
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission Model { get; set; } = new();
    private bool IsSubmitted { get; set; }

    private void HandleSubmit()
    {
        IsSubmitted = true;
    }

    private void ResetForm()
    {
        Model = new();
        IsSubmitted = false;
    }

    private class RecipeSubmission
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be 100 characters or less.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = "";
    }
}

.star-rating {
    font-size: 2rem;
    cursor: pointer;
}

.star {
    color: #ccc;
    transition: color 0.2s;
}

.star.filled {
    color: #ffc107;
}

.star:hover {
    color: #ffdb4d;
}

