@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@Model.Title</strong>" with the community.</p>
        <button class="btn btn-primary" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
                <option value="Beverages">Beverages</option>
                <option value="Baking">Baking</option>
                <option value="Vegetarian">Vegetarian</option>
            </InputSelect>
            <ValidationMessage For="() => Model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Model.Ingredients"
                           placeholder="Enter one ingredient per line" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
            <div class="form-text">Enter one ingredient per line.</div>
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Model.Steps"
                           placeholder="Enter one step per line" />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
            <div class="form-text">Enter one step per line.</div>
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission Model { get; set; } = new();
    private bool IsSubmitted { get; set; }

    private void HandleSubmit()
    {
        IsSubmitted = true;
    }

    private void ResetForm()
    {
        Model = new();
        IsSubmitted = false;
    }

    private class RecipeSubmission
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be 100 characters or less.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = "";
    }
}

